332→    /// Pause capture. Transitions: capturing → paused.
333→    pub fn pause_capture(&mut self) -> Result<(), CaptureError> {
334→        let duration = {
335→            let s = self.session_state.lock();
336→            match &s.state {
337→                CaptureState::Capturing { duration_secs } => *duration_secs,
338→                _ => {
339→                    return Err(CaptureError::ConfigurationFailed(
