357→    pub fn resume_capture(&mut self) -> Result<(), CaptureError> {
358→        let duration = {
359→            let s = self.session_state.lock();
360→            match &s.state {
361→                CaptureState::Paused { duration_secs } => *duration_secs,
362→                _ => {
363→                    return Err(CaptureError::ConfigurationFailed(
364→                        "can only resume from paused state".into(),
365→                    ))
366→                }
367→            }
368→        };
369→
370→        {
371→            let mut s = self.session_state.lock();
372→            if let Some(pause_start) = s.last_pause_time.take() {
373→                s.paused_duration += pause_start.elapsed();
374→            }
375→        }
376→        self.set_state(CaptureState::Capturing {
377→            duration_secs: duration,
378→        });
379→        Ok(())
380→    }
