382→    /// Stop capture, finalize file, return result.
383→    /// Transitions: capturing/paused → stopping → completed/failed.
384→    pub fn stop_capture(&mut self) -> Result<RecordingResult, CaptureError> {
385→        {
386→            let s = self.session_state.lock();
387→            if !s.state.is_capturing() && !s.state.is_paused() {
388→                return Err(CaptureError::ConfigurationFailed(
389→                    "can only stop from capturing or paused state".into(),
390→                ));
391→            }
392→        }
393→
394→        self.set_state(CaptureState::Stopping);
395→
396→        // Stop capture providers
397→        let _ = self.mic.stop();
398→        let _ = self.system.stop();
399→
400→        // Stop processing and timer threads
401→        self.processing_running.store(false, Ordering::SeqCst);
402→        self.timer_running.store(false, Ordering::SeqCst);
403→
404→        if let Some(handle) = self.processing_handle.take() {
405→            let _ = handle.join();
406→        }
407→        if let Some(handle) = self.timer_handle.take() {
408→            let _ = handle.join();
409→        }
410→
411→        // Flush remaining buffers one final time
412→        self.process_buffers_once();
413→
414→        // Finalize file
415→        let config = self.config.as_ref().unwrap();
416→        let file_path = self.file_path.as_ref().unwrap().clone();
417→        let detected_rate = self.session_state.lock().detected_mic_rate;
418→        let actual_rate = detected_rate.map(|r| r.min(config.sample_rate));
419→
420→        let checksum = {
421→            let mut writer_guard = self.writer.lock();
422→            if let Some(ref mut writer) = *writer_guard {
423→                let cs = writer.close(actual_rate, config.channels, config.bit_depth)?;
424→                *writer_guard = None;
425→                cs
426→            } else {
427→                return Err(CaptureError::StorageError("file writer not available".into()));
428→            }
429→        };
430→
431→        let duration = self.session_state.lock().elapsed_duration();
432→
433→        let metadata = match config.mixing_strategy {
434→            MixingStrategy::Separated => RecordingMetadata::new_separated(
435→                duration,
436→                &file_path.to_string_lossy(),
437→                &checksum,
438→                config.encryptor.is_some(),
439→                config.encryptor.as_ref().map(|e| e.algorithm().to_string()),
440→                config
441→                    .encryptor
442→                    .as_ref()
443→                    .and_then(|e| e.key_metadata().get("keyId").cloned()),
444→            ),
445→            MixingStrategy::Blended | MixingStrategy::Multichannel => RecordingMetadata::new_stereo(
446→                duration,
447→                &file_path.to_string_lossy(),
448→                &checksum,
449→                config.encryptor.is_some(),
450→                config.encryptor.as_ref().map(|e| e.algorithm().to_string()),
451→                config
452→                    .encryptor
453→                    .as_ref()
454→                    .and_then(|e| e.key_metadata().get("keyId").cloned()),
455→            ),
456→        };
457→
458→        // Close PCM sidecar files
459→        *self.mic_pcm_writer.lock() = None;
460→        *self.system_pcm_writer.lock() = None;
461→
462→        // Collect PCM sidecar paths
463→        let mut raw_pcm_file_paths = Vec::new();
464→        if config.export_raw_pcm {
465→            if let Some(ref p) = self.mic_pcm_path {
466→                raw_pcm_file_paths.push(p.clone());
467→            }
468→            if let Some(ref p) = self.system_pcm_path {
469→                raw_pcm_file_paths.push(p.clone());
470→            }
471→        }
472→
473→        let result = RecordingResult {
474→            file_path: file_path.clone(),
475→            duration_secs: duration,
476→            metadata,
477→            checksum,
478→            raw_pcm_file_paths,
479→        };
480→
481→        self.set_state(CaptureState::Completed(Box::new(result.clone())));
482→
483→        if let Some(ref delegate) = self.delegate {
484→            delegate.on_capture_finished(&result);
485→        }
486→
487→        // Reset for next session
488→        self.session_state.lock().state = CaptureState::Idle;
489→
490→        Ok(result)
491→    }
492→
493→    // --- Internal helpers ---
494→
495→    fn set_state(&self, new_state: CaptureState) {
496→        {
497→            let mut s = self.session_state.lock();
498→            s.state = new_state.clone();
499→        }
500→        if let Some(ref delegate) = self.delegate {
501→            delegate.on_state_changed(&new_state);
502→        }
503→    }
504→
505→    /// Start the background processing loop that reads ring buffers,
506→    /// mixes audio, and writes to the encrypted file.
507→    fn start_processing_loop(&mut self, output_rate: f64) {
508→        self.processing_running.store(true, Ordering::SeqCst);
509→
510→        let running = Arc::clone(&self.processing_running);
511→        let session_state = Arc::clone(&self.session_state);
512→        let mic_buf = Arc::clone(&self.mic_buffer);
513→        let sys_buf = Arc::clone(&self.system_buffer);
514→        let writer = Arc::clone(&self.writer);
515→        let mixer = self.mixer.clone();
516→        let ctx = ProcessingContext {
517→            enable_system: self.config.as_ref().map(|c| c.enable_system_capture).unwrap_or(false),
518→            chunk_size: (output_rate * 0.1) as usize, // 100ms of frames
519→            mixing_strategy: self
520→                .config
521→                .as_ref()
522→                .map(|c| c.mixing_strategy.clone())
523→                .unwrap_or_default(),
524→            channel_buffer_callback: self.channel_buffer_callback.clone(),
525→            export_raw_pcm: self.config.as_ref().map(|c| c.export_raw_pcm).unwrap_or(false),
526→            mic_pcm_writer: Arc::clone(&self.mic_pcm_writer),
527→            system_pcm_writer: Arc::clone(&self.system_pcm_writer),
528→        };
529→
530→        let handle = thread::Builder::new()
531→            .name("audio-processing".into())
532→            .spawn(move || {
533→                while running.load(Ordering::SeqCst) {
534→                    thread::sleep(Duration::from_millis(100));
535→
536→                    // Only process during capturing state
537→                    let is_capturing = {
538→                        let s = session_state.lock();
539→                        s.state.is_capturing()
540→                    };
541→                    if !is_capturing {
542→                        continue;
543→                    }
544→
545→                    Self::process_buffers_inner(&mic_buf, &sys_buf, &writer, &mixer, &session_state, &ctx);
546→                }
547→            })
548→            .expect("failed to spawn processing thread");
549→
550→        self.processing_handle = Some(handle);
551→    }
552→
553→    /// Start the duration update timer (250ms).
554→    fn start_duration_timer(&mut self) {
555→        self.timer_running.store(true, Ordering::SeqCst);
556→
557→        let running = Arc::clone(&self.timer_running);
558→        let session_state = Arc::clone(&self.session_state);
559→        let delegate = self.delegate.clone();
560→
561→        let handle = thread::Builder::new()
562→            .name("duration-timer".into())
563→            .spawn(move || {
564→                while running.load(Ordering::SeqCst) {
565→                    thread::sleep(Duration::from_millis(250));
566→
567→                    let mut s = session_state.lock();
568→                    if let CaptureState::Capturing { .. } = &s.state {
569→                        let dur = s.elapsed_duration();
570→                        s.state = CaptureState::Capturing { duration_secs: dur };
571→                        let levels = s.levels;
572→                        drop(s);
573→
574→                        if let Some(ref d) = delegate {
575→                            d.on_levels_updated(&levels);
576→                        }
577→                    }
578→                }
579→            })
580→            .expect("failed to spawn timer thread");
581→
582→        self.timer_handle = Some(handle);
583→    }
584→
585→    /// One-shot buffer processing (for final flush).
586→    fn process_buffers_once(&self) {
587→        let config = match &self.config {
588→            Some(c) => c,
589→            None => return,
590→        };
591→
592→        let ctx = ProcessingContext {
593→            enable_system: config.enable_system_capture,
594→            chunk_size: (config.sample_rate * 0.1) as usize,
595→            mixing_strategy: config.mixing_strategy.clone(),
596→            channel_buffer_callback: self.channel_buffer_callback.clone(),
597→            export_raw_pcm: config.export_raw_pcm,
598→            mic_pcm_writer: Arc::clone(&self.mic_pcm_writer),
599→            system_pcm_writer: Arc::clone(&self.system_pcm_writer),
600→        };
601→
602→        Self::process_buffers_inner(
603→            &self.mic_buffer,
604→            &self.system_buffer,
605→            &self.writer,
606→            &self.mixer,
607→            &self.session_state,
608→            &ctx,
609→        );
610→    }
611→
612→    /// Core buffer processing: read ring buffers → mix → convert to PCM → write.
613→    fn process_buffers_inner(
614→        mic_buf: &Mutex<RingBuffer>,
615→        sys_buf: &Mutex<RingBuffer>,
616→        writer: &Mutex<Option<EncryptedFileWriter>>,
617→        mixer: &StereoMixer,
618→        session_state: &Mutex<SessionState>,
619→        ctx: &ProcessingContext,
620→    ) {
621→        let mic_samples: Vec<f32>;
622→        let system_samples: Vec<f32>;
623→
624→        if ctx.enable_system {
625→            // System audio drives timing
626→            let system_frames_available = sys_buf.lock().count() / 2;
627→            let frames_to_process = system_frames_available.min(ctx.chunk_size);
628→            if frames_to_process == 0 {
629→                return;
630→            }
631→
632→            system_samples = sys_buf.lock().read(frames_to_process * 2);
633→            mic_samples = mic_buf.lock().read(frames_to_process);
634→        } else {
635→            // Mic-only mode
636→            mic_samples = mic_buf.lock().read(ctx.chunk_size);
637→            system_samples = Vec::new();
638→            if mic_samples.is_empty() {
639→                return;
640→            }
641→        }
642→
643→        // Deliver raw channel buffers before mixing
644→        if let Some(ref cb) = ctx.channel_buffer_callback {
645→            let buffers = ChannelBuffers {
646→                mic_samples: mic_samples.clone(),
647→                system_samples: system_samples.clone(),
648→                sample_rate: mixer.target_sample_rate,
649→                timestamp_unix_secs: {
650→                    use std::time::{SystemTime, UNIX_EPOCH};
651→                    SystemTime::now()
652→                        .duration_since(UNIX_EPOCH)
653→                        .map(|d| d.as_secs_f64())
654→                        .unwrap_or(0.0)
655→                },
656→            };
657→            cb(&buffers);
658→        }
659→
660→        // Write raw PCM sidecars if enabled
661→        if ctx.export_raw_pcm {
662→            let mic_pcm = mixer.convert_to_int16_pcm(&mic_samples);
663→            let system_pcm = mixer.convert_to_int16_pcm(&system_samples);
664→            if let Some(ref mut f) = *ctx.mic_pcm_writer.lock() {
665→                use std::io::Write;
666→                let _ = f.write_all(&mic_pcm);
667→            }
668→            if let Some(ref mut f) = *ctx.system_pcm_writer.lock() {
669→                use std::io::Write;
670→                let _ = f.write_all(&system_pcm);
671→            }
672→        }
673→
674→        // Mix according to strategy
675→        let stereo = mixer.mix(&mic_samples, &system_samples, &ctx.mixing_strategy);
676→
677→        // Convert to 16-bit PCM
678→        let pcm = mixer.convert_to_int16_pcm(&stereo);
679→
680→        // Update diagnostics
681→        {
682→            let mut s = session_state.lock();
683→            s.diagnostics.mix_cycles += 1;
684→            s.diagnostics.bytes_written += pcm.len() as u64;
685→        }
686→
687→        // Write to file
688→        if let Some(ref mut w) = *writer.lock() {
689→            if let Err(e) = w.write(&pcm) {
690→                log::error!("Failed to write audio data: {}", e);
691→            }
692→        }
693→    }
694→}
