 12→/// Streaming WAV file writer with optional AES-256-GCM chunk encryption.
 13→///
 14→/// Ports Swift's `EncryptedFileWriter` actor. In Rust, protect with
 15→/// `Mutex` for cross-thread access.
 16→///
 17→/// ## File Format
 18→///
 19→/// **Plaintext (no encryptor):**
 20→/// ```text
 21→/// [44-byte WAV header]
 22→/// [raw 16-bit PCM data...]
 23→/// ```
 24→///
 25→/// **Encrypted (with encryptor):**
 26→/// ```text
 27→/// [44-byte WAV header — unencrypted]
 28→/// [Chunk 1: 4-byte LE length | sealed box (nonce + ciphertext + tag)]
 29→/// [Chunk 2: ...]
 30→/// ...
 31→/// ```
 32→pub struct EncryptedFileWriter {
 33→    file_path: PathBuf,
 34→    encryptor: Option<Box<dyn CaptureEncryptor>>,
 35→    file: Option<File>,
 36→    total_bytes_written: u64,
 37→    is_open: bool,
 38→}
 39→
 40→impl EncryptedFileWriter {
 41→    pub fn new(file_path: PathBuf, encryptor: Option<Box<dyn CaptureEncryptor>>) -> Self {
 42→        Self {
 43→            file_path,
 44→            encryptor,
 45→            file: None,
 46→            total_bytes_written: 0,
 47→            is_open: false,
 48→        }
 49→    }
 50→
 51→    /// Open the file and write the initial 44-byte WAV header.
 52→    pub fn open(&mut self, config: &CaptureConfiguration) -> Result<(), CaptureError> {
 53→        if self.is_open {
 54→            return Ok(());
 55→        }
 56→
 57→        // Ensure output directory exists
 58→        if let Some(parent) = self.file_path.parent() {
 59→            fs::create_dir_all(parent)
 60→                .map_err(|e| CaptureError::StorageError(format!("failed to create directory: {}", e)))?;
 61→        }
 62→
 63→        let file = File::create(&self.file_path)
 64→            .map_err(|e| CaptureError::StorageError(format!("failed to create file: {}", e)))?;
 65→
 66→        self.file = Some(file);
 67→
 68→        let header = wav_format::generate_wav_header(
 69→            config.sample_rate as u32,
 70→            config.bit_depth,
 71→            config.channels,
 72→            0, // data size placeholder — updated on close
